// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

/**
 * @title BondCreditVault
 * @notice Minimal Phase-1 vault for accepting USDC deposits and allowing withdrawals.
 * @dev This contract is educational and intentionally simple: it uses `IERC20` for token
 * interactions, tracks per-user balances, and emits events on deposits/withdrawals.
 */
contract BondCreditVault {
    /// The ERC20 token used for deposits (USDC on XDC testnet)
    IERC20 public immutable usdc;

    /// Mapping of user => deposited amount (in token smallest units)
    mapping(address => uint256) public balances;

    /// Total deposits tracked by the contract (sum of all balances)
    uint256 public totalDeposits;

    /// Emitted when a user deposits tokens
    event Deposited(address indexed user, uint256 amount);

    /// Emitted when a user withdraws tokens
    event Withdrawn(address indexed user, uint256 amount);

    /**
     * @notice Construct the vault with the USDC token address.
     * @param _usdc The ERC20 token address used for deposits and withdrawals.
     */
    constructor(address _usdc) {
        require(_usdc != address(0), "USDC address cannot be zero");
        usdc = IERC20(_usdc);
    }

    /**
     * @notice Deposit USDC into the vault.
     * @dev Flow: user first calls `approve(vaultAddress, amount)` on the USDC token contract
     * (this happens off-chain or via the frontend). Then the user calls `deposit(amount)` on
     * this vault contract. The contract calls `usdc.transferFrom(msg.sender, address(this), amount)`
     * to pull tokens from the user into the vault. After a successful transfer the contract
     * updates accounting and emits a `Deposited` event.
     *
     * Note on security: `transferFrom` is an external call to the token contract. Here we
     * attempt to keep logic minimal: we call `transferFrom` first, then update internal
     * accounting on success. For typical well-behaved ERC20 tokens this is safe. If you
     * plan to accept tokens that could re-enter, consider applying additional protection.
     *
     * @param amount The number of token smallest units to deposit (must be > 0).
     */
    function deposit(uint256 amount) external {
        require(amount > 0, "Deposit amount must be > 0");

        // transferFrom: requires prior approval by the user for this contract to spend tokens.
        // The typical frontend flow is:
        // 1) User calls `USDC.approve(vaultAddress, amount)` from their wallet (meta-mask or XDC wallet).
        // 2) After the approval transaction confirms, the user calls `vault.deposit(amount)`.
        // 3) `transferFrom` pulls tokens from the user's balance into this contract.
        //
        // If `transferFrom` returns false or reverts, the deposit will revert and no state changes
        // below will execute.
        bool ok = usdc.transferFrom(msg.sender, address(this), amount);
        require(ok, "USDC transferFrom failed");

        // Update accounting AFTER the transfer succeeds. We track per-user balances and
        // the global totalDeposits value.
        balances[msg.sender] += amount;
        totalDeposits += amount;

        // Emit an event so off-chain services and frontends can track deposits efficiently.
        emit Deposited(msg.sender, amount);
    }

    /**
     * @notice Withdraw previously deposited USDC from the vault.
     * @dev To protect against reentrancy risks during token transfer, we update internal
     * accounting (reduce balances and totalDeposits) before making the external `transfer` call.
     * This ensures that even if the token contract is malicious and attempts reentrant calls,
     * the user's balance has already been decreased.
     *
     * @param amount The number of token smallest units to withdraw (must be > 0 and <= balance).
     */
    function withdraw(uint256 amount) external {
        require(amount > 0, "Withdraw amount must be > 0");
        uint256 userBalance = balances[msg.sender];
        require(userBalance >= amount, "Insufficient balance");

        // Effects: reduce stored balances before external call
        balances[msg.sender] = userBalance - amount;
        totalDeposits -= amount;

        // Interaction: transfer tokens back to the user. We prefer `transfer` here.
        bool ok = usdc.transfer(msg.sender, amount);
        require(ok, "USDC transfer failed");

        emit Withdrawn(msg.sender, amount);
    }

    /**
     * @notice Get the deposited token balance of a user.
     * @param user The address of the user to query.
     * @return The user's deposited token amount (in token smallest units).
     */
    function getBalance(address user) external view returns (uint256) {
        return balances[user];
    }
}

